/**
 * Safe register debug override plugins.
 *
 * @param logger The logger to use for logging errors.
 * @param debugOverride The debug override to register.
 * @param plugins The plugins to register.
 */
function safeRegisterDebugOverridePlugins(logger, debugOverride, plugins) {
    plugins.forEach((plugin) => {
        try {
            plugin.registerDebug?.(debugOverride);
        }
        catch (error) {
            logger.error(`Exception thrown registering plugin ${internal.safeGetName(logger, plugin)}.`);
        }
    });
}

function readFlagsFromBootstrap(logger, data) {
    // If the bootstrap data came from an older server-side SDK, we'll have just a map of keys to values.
    // Newer SDKs that have an allFlagsState method will provide an extra "$flagsState" key that contains
    // the rest of the metadata we want. We do it this way for backward compatibility with older JS SDKs.
    const keys = Object.keys(data);
    const metadataKey = '$flagsState';
    const validKey = '$valid';
    const metadata = data[metadataKey];
    if (!metadata && keys.length) {
        logger.warn('LaunchDarkly client was initialized with bootstrap data that did not include flag' +
            ' metadata. Events may not be sent correctly.');
    }
    if (data[validKey] === false) {
        logger.warn('LaunchDarkly bootstrap data is not available because the back end could not read the flags.');
    }
    const ret = {};
    keys.forEach((key) => {
        if (key !== metadataKey && key !== validKey) {
            let flag;
            if (metadata && metadata[key]) {
                flag = {
                    value: data[key],
                    ...metadata[key],
                };
            }
            else {
                flag = {
                    value: data[key],
                    version: 0,
                };
            }
            ret[key] = {
                version: flag.version,
                flag,
            };
        }
    });
    return ret;
}

/**
 * Creates endpoint paths for browser (client-side ID) FDv1 evaluation.
 *
 * @param clientSideId The client-side ID for this environment.
 */
function browserFdv1Endpoints(clientSideId) {
    return {
        polling: () => ({
            pathGet(encoding, plainContextString) {
                return `/sdk/evalx/${clientSideId}/contexts/${base64UrlEncode(plainContextString, encoding)}`;
            },
            pathReport(_encoding, _plainContextString) {
                return `/sdk/evalx/${clientSideId}/context`;
            },
            pathPost(_encoding, _plainContextString) {
                throw new Error('Post for FDv1 unsupported.');
            },
            pathPing(_encoding, _plainContextString) {
                throw new Error('Ping for polling unsupported.');
            },
        }),
        streaming: () => ({
            pathGet(encoding, plainContextString) {
                return `/eval/${clientSideId}/${base64UrlEncode(plainContextString, encoding)}`;
            },
            pathReport(_encoding, _plainContextString) {
                return `/eval/${clientSideId}`;
            },
            pathPost(_encoding, _plainContextString) {
                throw new Error('Post for FDv1 unsupported.');
            },
            pathPing(_encoding, _plainContextString) {
                return `/ping/${clientSideId}`;
            },
        }),
    };
}
